import {
  CHANGE,
  ARTICLEADD,
  LOVEARTICLEADD,
  LIVEARTICLEADD,
  TOPARTICLEADD
} from "./mutation_type";

export default {
  change({commit},str){
    commit(CHANGE,str)
  },
  articleAdd({commit},data){
    commit(ARTICLEADD,data)
  },
  loveArticleAdd({commit},data){
    commit(LOVEARTICLEADD,data)
  },
  liveArticleAdd({commit},data){
    commit(LIVEARTICLEADD,data)
  },
  topArticleAdd({commit},data){
    commit(TOPARTICLEADD,data)
  }
}



