<template>
  <nav class="navbar navbar-default navbar-fixed-top " role="navigation">
    <div class="container-fluid">
      <div class="navbar-header">
        <button type="button" class="navbar-toggle collapsed" data-toggle="collapse" data-target="#navbar" aria-expanded="false" aria-controls="navbar">
          <span class="sr-only">Toggle navigation</span>
          <span class="icon-bar"></span>
          <span class="icon-bar"></span>
          <span class="icon-bar"></span>
        </button>
        <a class="navbar-brand" href="/">江的私人空间</a>
      </div>
      <div>
        <ul id="navbar" class="nav navbar-nav navbar-collapse collapse">
          <li v-for="(item,index) in items" :key="index" :class="{active:isActive==item.url}" @click="changeClass(item.url)">
            <router-link :to="item.url">{{item.title}}</router-link>
          </li>
        </ul>
      </div>
    </div>
  </nav>
</template>

<script>
  export default {
    name: "headers",
    data()
    {
      return{
          items:[
            {url:'/home',title:'主页'},
            {url:'/like',title:'我喜欢的文章'},
            {url:'/aboutme',title:'关于我'},
            {url:'/live',title:'生活'}
            ],
          isActive:"",
      }
    },
    methods:{
      changeClass(url){
          this.isActive = url;
      }
    },
    created(){

      //1.刷新页面样式改变明智的解决方案
      this.isActive = this.$route.path
      // var temp = this.$route.path;
      //2.刷新页面样式改变的脑瘫解决方案
      // switch (temp){
      //   case '/home':
      //     this.isActive = 0;
      //     break;
      //   case '/like':
      //     this.isActive=1;
      //     break;
      //   case '/aboutme':
      //     this.isActive=2;
      //     break;
      //   case '/live':
      //     this.isActive=3;
      //     break;
      //   default:
      //     this.isActive=999;
      // }
    }
  }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">

</style>



